// Auto-generated base64 data for sample.xlsx used in selftest.
export const SAMPLE_XLSX_BASE64 = '';
export function getSampleWorkbookBytes() {
  const binaryString = atob(SAMPLE_XLSX_BASE64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
}
